我有一个音频处理的环形缓冲区，目前用 Vec 存储，通道数和缓冲区深度在初始化后就不变了。帮我用 const generics 重构，消除运行时边界检查。

```rust
pub struct RingBuffer {
    channels: usize,
    depth: usize,
    data: Vec<Vec<f32>>,
    write_pos: Vec<usize>,
}

impl RingBuffer {
    pub fn new(channels: usize, depth: usize) -> Self {
        Self {
            channels,
            depth,
            data: vec![vec![0.0; depth]; channels],
            write_pos: vec![0; channels],
        }
    }

    pub fn push(&mut self, channel: usize, sample: f32) {
        assert!(channel < self.channels);
        let pos = self.write_pos[channel];
        self.data[channel][pos % self.depth] = sample;
        self.write_pos[channel] = pos + 1;
    }

    pub fn read(&self, channel: usize, delay: usize) -> f32 {
        assert!(channel < self.channels);
        assert!(delay < self.depth);
        let pos = (self.write_pos[channel] + self.depth - delay - 1) % self.depth;
        self.data[channel][pos]
    }

    pub fn process_block(&mut self, input: &[Vec<f32>], output: &mut [Vec<f32>]) {
        assert_eq!(input.len(), self.channels);
        for ch in 0..self.channels {
            for (i, &sample) in input[ch].iter().enumerate() {
                self.push(ch, sample);
                output[ch][i] = self.read(ch, 0);
            }
        }
    }
}
```

我在写一个小型矩阵库，支持矩阵乘法。想用 const generics 让维度不匹配在编译时报错，而不是运行时 panic。

```rust
pub struct Matrix {
    rows: usize,
    cols: usize,
    data: Vec<f32>,
}

impl Matrix {
    pub fn new(rows: usize, cols: usize) -> Self {
        Self {
            rows,
            cols,
            data: vec![0.0; rows * cols],
        }
    }

    pub fn get(&self, r: usize, c: usize) -> f32 {
        assert!(r < self.rows && c < self.cols);
        self.data[r * self.cols + c]
    }

    pub fn set(&mut self, r: usize, c: usize, val: f32) {
        assert!(r < self.rows && c < self.cols);
        self.data[r * self.cols + c] = val;
    }

    pub fn mul(&self, other: &Matrix) -> Matrix {
        assert_eq!(self.cols, other.rows, "dimension mismatch");
        let mut result = Matrix::new(self.rows, other.cols);
        for i in 0..self.rows {
            for j in 0..other.cols {
                let mut sum = 0.0;
                for k in 0..self.cols {
                    sum += self.get(i, k) * other.get(k, j);
                }
                result.set(i, j, sum);
            }
        }
        result
    }

    pub fn transpose(&self) -> Matrix {
        let mut result = Matrix::new(self.cols, self.rows);
        for i in 0..self.rows {
            for j in 0..self.cols {
                result.set(j, i, self.get(i, j));
            }
        }
        result
    }
}
```

我在解析一个分层网络协议，每层有固定的 header 大小和 payload 对齐要求。目前这些都是运行时常量，想改成 const generics 让编译器验证。

```rust
pub struct ProtocolLayer {
    header_size: usize,
    alignment: usize,
    buffer: Vec<u8>,
}

impl ProtocolLayer {
    pub fn new(header_size: usize, alignment: usize, max_payload: usize) -> Self {
        let total = header_size + Self::align_up(max_payload, alignment);
        Self {
            header_size,
            alignment,
            buffer: vec![0u8; total],
        }
    }

    fn align_up(size: usize, align: usize) -> usize {
        (size + align - 1) / align * align
    }

    pub fn header(&self) -> &[u8] {
        &self.buffer[..self.header_size]
    }

    pub fn payload(&self) -> &[u8] {
        &self.buffer[self.header_size..]
    }

    pub fn write_header(&mut self, data: &[u8]) {
        assert_eq!(data.len(), self.header_size);
        self.buffer[..self.header_size].copy_from_slice(data);
    }

    pub fn write_payload(&mut self, data: &[u8]) {
        let aligned_len = Self::align_up(data.len(), self.alignment);
        assert!(self.header_size + aligned_len <= self.buffer.len());
        self.buffer[self.header_size..self.header_size + data.len()].copy_from_slice(data);
    }
}

pub struct ProtocolStack {
    layers: Vec<ProtocolLayer>,
}

impl ProtocolStack {
    pub fn total_header_size(&self) -> usize {
        self.layers.iter().map(|l| l.header_size).sum()
    }
}
